<?php require_once __DIR__ . '/../includes/db.php'; if($_SERVER['REQUEST_METHOD']==='POST'){ $name=mysqli_real_escape_string($conn,$_POST['name']??''); $email=mysqli_real_escape_string($conn,$_POST['email']??''); $phone=mysqli_real_escape_string($conn,$_POST['phone']??''); $address=mysqli_real_escape_string($conn,$_POST['address']??''); $password=mysqli_real_escape_string($conn,$_POST['password']??''); mysqli_query($conn,"INSERT INTO users(name,email,phone,address,password,role) VALUES('$name','$email','$phone','$address','$password','customer')"); } redirect_to('auth/login.php'); ?>